+func TestEnsureNpmProject_Installs_WithFakeNpm(t *testing.T) {
+	fakeBin := t.TempDir()
+	writeExe(t, filepath.Join(fakeBin, "npm"), `#!/bin/sh
+set -e
+mkdir -p node_modules/chrome-cookies-secure
+echo '{}' > node_modules/chrome-cookies-secure/package.json
