+			t.Fatalf("bad form: %v", form)
+		}
+		if form.Get("client_secret") != "s" || form.Get("client_id") != "android" || form.Get("scope") != "API_CUSTOMER" {
+			t.Fatalf("bad oauth fields: %v", form)
+		}
+
+		w.Header().Set("Content-Type", "application/json")
